4	/**
5	 * Returns the next generation of live cells per Conway's Game of Life rules.
6	 *
7	 * Rules:
8	 *  - Underpopulation: a live cell with fewer than 2 live neighbors dies.
9	 *  - Survival: a live cell with 2 or 3 live neighbors lives on.
10	 *  - Overpopulation: a live cell with more than 3 live neighbors dies.
11	 *  - Reproduction: a dead cell with exactly 3 live neighbors becomes alive.
12	 */
13	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
14	  [-1, -1], [-1, 0], [-1, 1],
15	  [ 0, -1],          [ 0, 1],
16	  [ 1, -1], [ 1, 0], [ 1, 1],
17	];
18	
19	const toKey = ([x, y]: Cell): string => `${x},${y}`;
20	
21	export function nextGeneration(liveCells: Cell[]): Cell[] {
22	  const liveSet = new Set(liveCells.map(toKey));
23	  const countLiveNeighbors = ([x, y]: Cell): number =>
24	    NEIGHBOR_OFFSETS.filter(([dx, dy]) => liveSet.has(toKey([x + dx, y + dy]))).length;
25	
26	  return liveCells.filter((cell) => {
27	    const neighborCount = countLiveNeighbors(cell);
28	    return neighborCount === 2 || neighborCount === 3;
29	  });
30	}
