export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(toKey));
  const countLiveNeighbors = ([x, y]: Cell): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) => liveSet.has(toKey([x + dx, y + dy]))).length;

  const survives = (cell: Cell): boolean => {
    const neighborCount = countLiveNeighbors(cell);
    return neighborCount === 2 || neighborCount === 3;
  };

  return liveCells.filter(survives);
}
